mapper.sql:
SELECT T.ID, T.COUPON_ID, T.COUPON_NUMBER, T.USER_ID, T.USED_TIME, T.ADD_TIME, T.ORDER_ID, T.COUPON_STATUS, T.SOURCE_KEY, T.REFERRER, U.NICKNAME FROM MALL_USER_COUPON T LEFT JOIN WX_USER U ON T.USER_ID = U.ID WHERE 1=1
AND T.ID = #{params.id}
AND T.NAME LIKE '%${params.name}%'

mapper.select:
select a.* from mall_user_coupon a
left join mall_coupon b on b.id = a.coupon_id
where 1 = 1

    and a.coupon_number = #{couponNumber}


    and a.user_id = #{userId}


    and b.send_type = #{sendType}


    and a.referrer = #{referrer}


    and a.source_key = #{sourceKey}



        order by ${sidx} ${order}


        order by id desc



    limit #{offset}, #{limit}
